from __future__ import annotations
import json, time
from dataclasses import dataclass, field, asdict
from pathlib import Path

@dataclass(frozen=True)
class RetrievalEvent:
    lineage_id:       str           # links to PromptLineageRecord
    query_hash:       str           # SHA-256 of the query text
    collection:       str
    timestamp_utc:    float
    user_label:       str           # user's clearance at retrieval time
    candidates_count: int           # total hits from vector store before filtering
    served_chunks:    list[str]     # chunk_ids actually injected into the prompt
    blocked_chunks:   list[str]     # chunk_ids filtered out (label > user clearance)
    retracted_chunks: list[str]     # chunk_ids skipped due to doc retraction

    def to_ndjson_line(self) -> str:
        return json.dumps(asdict(self), default=str)


class RetrievalLog:
    def __init__(self, path: Path):
        self.path = path

    def append(self, event: RetrievalEvent) -> None:
        with self.path.open("a") as f:
            f.write(event.to_ndjson_line() + "\n")

    def find_by_chunk(self, chunk_id: str) -> list[RetrievalEvent]:
        results = []
        for line in self.path.read_text().splitlines():
            if not line.strip():
                continue
            data = json.loads(line)
            if chunk_id in data.get("served_chunks", []):
                results.append(RetrievalEvent(**data))
        return results
